final:
module alu(
    input [31:0] obf_A, B, 
    input [2:0] F, 
    output reg [31:0] Y, 
    output reg Zero
);

always @*
begin
    case(F)
        3'b000: Y <= obf_A & B;
        3'b001: Y <= obf_A | B;
        3'b010: Y <= obf_A + B;
        3'b011: Y <= obf_A & ~B;
        3'b101: Y <= obf_A + ~B;
        3'b110: Y <= obf_A - B;
        3'b111: Y <= (obf_A < B) ? 1 : 0;
        default: Y <= 0;
    endcase
    Zero <= (Y == 0) ? 1 : 0;
end

endmodule
